import api from './api';

export const getApplicants = async (params) => {
    try {
        const response = await api.get('/admin/applicants', { params });
        return response.data;
    } catch (error) {
        throw error.response?.data || error;
    }
};

export const updateApplicantOCR = async (applicantIds = [], ocrDisabled = false) => {
    try {
        const response = await api.patch('/admin/applicants/ocr', {
            applicant_ids: applicantIds,
            ocr_disabled: ocrDisabled
        });
        return response.data;
    } catch (error) {
        throw error.response?.data || error;
    }
};

export const getApplicantById = async (id) => {
    try {
        const response = await api.get(`/admin/applicants/${id}`);
        return response.data;
    } catch (error) {
        throw error.response?.data || error;
    }
};

export const getApplicantApplications = async (applicantId) => {
    try {
        // Assuming there is an endpoint to get applications for a specific applicant by admin
        // Or it might be returned in getApplicantById. 
        // Based on typical patterns:
        const response = await api.get(`/admin/applicants/${applicantId}/applications`);
        return response.data;
    } catch (error) {
        throw error.response?.data || error;
    }
};
